INSERT INTO galleries (id, name, slug, description, address, area, type, website, instagram, email, phone, submission_policy, founded_year, logo_url, cover_image_url, social_links, is_featured, subscription_active) VALUES
  ('11111111-0001-0001-0001-000000000001', 'Green Art Gallery', 'green-art-gallery', 'One of Dubai''s oldest contemporary art galleries, representing a multi-generational mix of artists from the Middle East, Turkey, South Asia and beyond with a research-based approach. Originally established in a Jumeirah villa salon in 1995, it relocated to Alserkal Avenue in 2010.', 'Warehouse 28, Alserkal Avenue, Street 8, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.gagallery.com', 'greenartgallerydxb', 'info@gagallery.com', '+971 4 346 9305', '', 1995, NULL, NULL, '{"facebook": "greenartgallery", "twitter": ""}', false, true),
  ('11111111-0001-0001-0001-000000000002', 'The Third Line', 'the-third-line', 'A pioneering Dubai-based contemporary art gallery representing artists locally, regionally and internationally with a focus on the Middle East and its diaspora. Publishes art books in English and Arabic and hosts non-profit alternative programmes alongside its commercial exhibitions.', 'Warehouse 78 & 80, Alserkal Avenue, Street 8, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://thethirdline.com', 'thethirdline', 'art@thethirdline.com', '+971 4 341 1367', '', 2005, NULL, NULL, '{"facebook": "thethirdline", "twitter": "thethirdline"}', false, true),
  ('11111111-0001-0001-0001-000000000003', 'Lawrie Shabibi', 'lawrie-shabibi', 'A leading contemporary gallery in Alserkal Avenue focused on diasporic artists across generations and geographies. Founded by William Lawrie and Asmaa Al-Shabibi, it promotes artists from the Middle East, North Africa, Africa and South America, and organises art historical exhibitions alongside contemporary programming.', 'Unit 21, Alserkal Avenue, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.lawrieshabibi.com', 'lawrieshabibi', 'info@lawrieshabibi.com', '+971 4 346 9906', 'Not currently accepting unsolicited artist submissions.', 2011, NULL, NULL, '{"facebook": "lawrieshabibi", "twitter": "lawrieshabibi"}', false, true),
  ('11111111-0001-0001-0001-000000000004', 'CARBON 12', 'carbon-12', 'The first gallery in the UAE to initiate a comprehensive, firmly global programme of institution-grade artists. Internationally active, CARBON 12 promotes both established and emerging artists to the UAE contemporary art scene, with 6–8 annual exhibitions supplemented by publications and talks.', 'Unit 37, Alserkal Avenue, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.carbon12.art', 'carbon12gallery', 'info@carbon12dubai.com', '+971 4 340 6016', 'Not currently accepting unsolicited artist submissions.', 2008, NULL, NULL, '{"facebook": "Carbon12gallery", "twitter": ""}', false, true),
  ('11111111-0001-0001-0001-000000000005', 'Gallery Isabelle van den Eynde', 'gallery-isabelle-van-den-eynde', 'A contemporary art gallery representing a pluralistic roster of artists from the Middle East, North Africa and beyond. Known for conceptual works and dynamic installations, the gallery closely collaborates with artists to create insightful and provocative presentations.', 'Unit 17, Alserkal Avenue, Street 8, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.ivde.net', 'galleryisabelle', 'info@ivde.net', '+971 4 323 5052', '', 2010, NULL, NULL, '{"facebook": "GalleryIVDE", "twitter": ""}', false, true),
  ('11111111-0001-0001-0001-000000000006', 'Grey Noise', 'grey-noise', 'A contemporary art gallery representing emerging and established artists with a focus on experimental practice from South Asia, the Middle East, and Europe. Through active partnerships with curators and institutions worldwide, Grey Noise promotes new and experimental streams of thought in art and culture.', 'Unit 24, Alserkal Avenue, Street 8, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.greynoise.org', 'greynoisedxb', 'info@greynoise.org', '+971 4 379 0764', '', 2008, NULL, NULL, '{"facebook": "greynoise", "twitter": ""}', false, true),
  ('11111111-0001-0001-0001-000000000007', 'Ayyam Gallery', 'ayyam-gallery', 'A leading arts organisation managing the careers of diverse established and emerging artists, specialising in Arab and Iranian contemporary art. Maintains a multilingual publishing division and custodian programme managing artist estates. One of the founding galleries of Alserkal Avenue.', 'Warehouse 11, Alserkal Avenue, Street 8, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.ayyamgallery.com', 'ayyamgallery', 'dubai@ayyamgallery.com', '+971 4 323 6242', '', 2006, NULL, NULL, '{"facebook": "ayyamgallery", "twitter": "ayyamgallery"}', false, true),
  ('11111111-0001-0001-0001-000000000008', 'Elmarsa Gallery', 'elmarsa-gallery', 'A gallery specialising in both modern and contemporary North African and Middle Eastern art. Active in primary and secondary markets, representing influential 20th and 21st century artists from North Africa at spaces in Tunis, Dubai and Paris.', 'Unit 23, Alserkal Avenue, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.galerielmarsa.com', 'galerielmarsa', 'info@galerielmarsa.com', '+971 4 341 5806', '', 1994, NULL, NULL, '{"facebook": "galerielmarsa", "twitter": ""}', false, true),
  ('11111111-0001-0001-0001-000000000009', 'Leila Heller Gallery', 'leila-heller-gallery', 'One of the largest contemporary art galleries in the UAE and a pioneer in promoting creative dialogue between Western, Middle Eastern, Central and Southeast Asian artists. The gallery organises shows with world-renowned curators, hosts educational panels, film screenings and produces catalogues and books.', 'I-87, Alserkal Avenue, PO Box 413991, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.leilahellergallery.com', 'leilahellergallery', 'dubai@leilahellergallery.com', '+971 4 321 6942', '', 2015, NULL, NULL, '{"facebook": "leilahellergallery", "twitter": ""}', true, true),
  ('11111111-0001-0001-0001-000000000010', 'Custot Gallery Dubai', 'custot-gallery-dubai', 'A 700 m² gallery dedicated to modern and contemporary international art in the heart of Alserkal Avenue. Associated with the prestigious Waddington Custot gallery in London, it exhibits major blue-chip and contemporary artists in a grand warehouse setting.', 'Alserkal Avenue, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.custotgallerydubai.ae', 'custotgallerydubai', NULL, NULL, '', 2016, NULL, NULL, '{}', false, true),
  ('11111111-0001-0001-0001-000000000011', 'Tabari Artspace', 'tabari-artspace', 'A pioneering contemporary art gallery that has played a vital role in connecting international audiences and institutions to modern and contemporary MENA art for over two decades. Led by an all-women team, the gallery champions female artists and amplifies diverse perspectives through exhibitions, residencies, publishing and community events.', 'The Gate Village, Building 3, Level 2, DIFC, Dubai, UAE', 'DIFC', 'gallery', 'https://www.tabariartspace.com', 'tabari_artspace', 'gallery@tabariartspace.com', '+971 4 323 0820', '', 2003, NULL, NULL, '{"facebook": "Tabariartspace", "twitter": ""}', false, true),
  ('11111111-0001-0001-0001-000000000012', 'Perrotin Dubai', 'perrotin-dubai', 'The Dubai branch of the globally renowned Parisian gallery founded by Emmanuel Perrotin, presenting blue-chip and internationally established contemporary artists. Located in DIFC''s Gate Village, the 1,100 m² space opened in April 2025 as Perrotin''s twelfth global location.', 'Gate Village Building 5, Podium Level, 05 Sheikh Zayed Rd, DIFC, Dubai, UAE', 'DIFC', 'gallery', 'https://www.perrotin.com', 'galerieperrotin', 'dubai@perrotin.com', '+971 4 577 6851', '', 2025, NULL, NULL, '{"facebook": "galerieperrotin", "twitter": "galerieperrotin"}', true, true),
  ('11111111-0001-0001-0001-000000000013', 'Meem Gallery', 'meem-gallery', 'A leading international gallery for modern and contemporary Arab, North African and Iranian art. Meem maintains the Noor Library for Middle Eastern Art with 16,000+ resources and operates Meem Editions, an in-house publishing programme. Works by represented artists are held by MoMA, Tate Modern, the British Museum and the Guggenheim.', 'Unit 1, Kanoo Compound, 159 Umm Suqeim Road, Al Quoz 3, Dubai, UAE', 'Other', 'gallery', 'https://www.meemartgallery.com', 'meemgallery', 'info@meemartgallery.com', '+971 4 347 7883', '', 2007, NULL, NULL, '{}', false, true),
  ('11111111-0001-0001-0001-000000000014', 'XVA Gallery', 'xva-gallery', 'Located within the boutique XVA Hotel in Dubai''s historic Al Fahidi district, this gallery specialises in contemporary art from the Arab world, Iran and the Subcontinent. The intimate multi-room space challenges stereotypes and gives voice to diverse cultural identities.', 'Al Fahidi Neighbourhood, 312th Road, Bur Dubai, Dubai, UAE', 'Other', 'gallery', 'https://www.xvagallery.com', 'xvagallery', 'xva@xvagallery.com', '+971 4 353 5383', '', 2003, NULL, NULL, '{"facebook": "xvagallery", "twitter": ""}', false, true),
  ('11111111-0001-0001-0001-000000000015', '1X1 Art Gallery', '1x1-art-gallery', 'A 7,500 sq ft contemporary art space in Alserkal Avenue dedicated to modern and contemporary art from the Global South, with a historic focus on South Asian art. The gallery collaborates with international art fairs, museums and curators, and maintains a dedicated library and bookstore on South Asian art and literature.', 'Unit 10, Alserkal Avenue, Street 8, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.1x1artgallery.com', '1x1artgallery', 'info@1x1artgallery.com', '+971 4 341 1287', '', 1996, NULL, NULL, '{}', false, true),
  ('11111111-0001-0001-0001-000000000016', 'Opera Gallery Dubai', 'opera-gallery-dubai', 'The Dubai branch of the internationally established Opera Gallery network, showcasing modern and contemporary art including paintings, sculptures and photography. Features both blue-chip masters and emerging talent in a prominent DIFC location.', 'Gate Village Building 3, DIFC, Dubai, UAE', 'DIFC', 'gallery', 'https://www.operagallery.com/dubai', 'operagallery', 'dubai@operagallery.com', '+971 4 323 0909', '', 1994, NULL, NULL, '{"facebook": "operagallery", "twitter": "operagallery"}', false, true),
  ('11111111-0001-0001-0001-000000000017', 'Cuadro Fine Art Gallery', 'cuadro-gallery', 'A premier contemporary and modern art gallery in DIFC with four areas of focus: exhibitions, education, residency and consultation. The Cuadro Education Programme offers lectures, workshops and panel discussions, and the gallery provides artist residencies with exhibition opportunities.', 'Building 10, Gate Village, DIFC, Dubai, UAE', 'DIFC', 'gallery', 'https://www.cuadroart.com', 'cuadroart', NULL, NULL, '', 2008, NULL, NULL, '{}', false, true),
  ('11111111-0001-0001-0001-000000000018', 'Zawyeh Gallery', 'zawyeh-gallery', 'A gallery and cultural platform championing Palestinian artists and the broader Arab contemporary art scene. Zawyeh provides a voice for Palestinian heritage, roots and history through contemporary artistic expression, with a community-driven programme.', 'Alserkal Avenue, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.zawiyehgallery.com', 'zawiyehgallery', NULL, NULL, '', 2013, NULL, NULL, '{}', false, true),
  ('11111111-0001-0001-0001-000000000019', 'Ishara Art Foundation', 'ishara-art-foundation', 'A non-profit contemporary art institution in Alserkal Avenue dedicated exclusively to South Asian art. Ishara fosters dialogue between South Asian artists and the wider global art community through exhibitions, residencies and public programmes.', 'Alserkal Avenue, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.isharaartfoundation.org', 'isharaartfoundation', 'info@isharaartfoundation.org', NULL, '', 2018, NULL, NULL, '{}', false, true),
  ('11111111-0001-0001-0001-000000000020', 'Gulf Photo Plus', 'gulf-photo-plus', 'Dubai''s dedicated centre for all forms of photography, providing workshops, free artist talks and community events for local and international photographers. Home of the region''s longest-running international photography event, GPP Photo Week.', 'Alserkal Avenue, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.gulfphotoplus.com', 'gulfphotoplus', 'info@gulfphotoplus.com', NULL, '', 2007, NULL, NULL, '{"facebook": "gulfphotoplus", "twitter": "gulfphotoplus"}', false, true),
  ('11111111-0001-0001-0001-000000000021', 'Majlis Gallery', 'majlis-gallery', 'One of Dubai''s oldest galleries, occupying a restored traditional wind-tower courtyard building in the historic Al Fahidi neighbourhood. Focuses on fine art, ceramics, glass and crafts with a strong emphasis on Emirati and regional heritage.', 'Al Fahidi Neighbourhood, Bur Dubai, Dubai, UAE', 'Other', 'gallery', 'https://www.themajlisgallery.com', 'themajlisgallery', 'majlisgallery@hotmail.com', '+971 4 353 6233', '', 1976, NULL, NULL, '{}', false, true),
  ('11111111-0001-0001-0001-000000000022', 'Tashkeel', 'tashkeel', 'A multidisciplinary arts centre nurturing the development of contemporary art and design practices rooted in the UAE. Established by Sheikha Lateefa bint Maktoum, Tashkeel provides studios, workshops, gallery spaces and the Tashkeel Critical Practice Programme.', 'Street 10b, Al Fahidi, Bur Dubai, Dubai, UAE', 'Other', 'gallery', 'https://www.tashkeel.org', 'tashkeel', 'info@tashkeel.org', '+971 4 336 3313', '', 2008, NULL, NULL, '{"facebook": "tashkeel", "twitter": "tashkeelarts"}', false, true),
  ('11111111-0001-0001-0001-000000000023', 'Jameel Arts Centre', 'jameel-arts-centre', 'Dubai''s leading independent contemporary art institution, supported by Art Jameel, situated on the Jaddaf waterfront. Offers a sculpture park, exhibitions, research library, workshops and artist residencies. Widely praised as Dubai''s must-visit contemporary art institution.', 'Jaddaf Waterfront, Al Jaddaf, Dubai, UAE', 'Other', 'museum', 'https://www.jameelartsjameel.org', 'jameelarts', 'info@jameelarts.org', '+971 4 873 3000', '', 2018, NULL, NULL, '{"facebook": "jameelarts", "twitter": "jameelarts"}', true, true),
  ('11111111-0001-0001-0001-000000000024', 'Salsali Private Museum', 'salsali-private-museum', 'A private museum dedicated to contemporary art by artists and collectors from the region. Houses Iranian collector Ramin Salsali''s collection of over 800 works, alongside rotating guest collections and travelling exhibitions from around the world.', 'Alserkal Avenue, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'museum', 'https://www.spm.ae', 'salsaliprivatemuseum', 'info@spm.ae', '+971 4 323 5613', '', 2011, NULL, NULL, '{}', false, true),
  ('11111111-0001-0001-0001-000000000025', 'AKKA Project', 'akka-project-dubai', 'A vibrant gallery presenting multidimensional exhibitions and immersive art experiences with expertise in African contemporary art. AKKA Project bridges the international art world with the UAE''s diverse cultural scene, featuring emerging and established African artists.', 'Alserkal Avenue, Al Quoz 1, Dubai, UAE', 'Alserkal Avenue', 'gallery', 'https://www.akkaproject.com', 'akkaprojectspace', NULL, NULL, '', 2014, NULL, NULL, '{}', false, true),
  ('11111111-0001-0001-0001-000000000026', 'Oblong Contemporary Art Gallery', 'oblong-contemporary', 'A contemporary art gallery in Dubai''s Al Quoz area representing an international roster of painters, sculptors and mixed-media artists. Hosts rotating solo and group exhibitions and participates in local arts initiatives including the Al Quoz Creative Entrepreneurship Forum.', 'Al Quoz, Dubai, UAE', 'Other', 'gallery', 'https://oblongcontemporary.com', 'oblong_contemporary', NULL, NULL, '', 2015, NULL, NULL, '{}', false, true),
  ('11111111-0001-0001-0001-000000000027', 'Foundry', 'foundry-dubai', 'A contemporary art gallery and co-working space in Business Bay championing underrepresented and independent artists. Visitors can see artists at work in the open studio environment alongside exhibitions of paintings, sculptures and photography. Also features a creative library, podcast room and café.', 'Business Bay, Dubai, UAE', 'Other', 'gallery', NULL, 'foundry.dubai', NULL, NULL, '', 2020, NULL, NULL, '{}', false, true),
  ('11111111-0001-0001-0001-000000000028', 'Showcase Gallery', 'showcase-gallery', 'One of the UAE''s first established galleries, now a leading contemporary art space specialising in works from accomplished Middle Eastern and African artists. Offers an in-house framing service with over 300 options.', 'Al Quoz, Dubai, UAE', 'Other', 'gallery', NULL, 'showcasegallery_dubai', NULL, NULL, '', 1995, NULL, NULL, '{}', false, true)
INSERT INTO artists (id, name, slug, nationality, city, bio, website, instagram, open_to_collaboration, is_verified, pro_subscription_active) VALUES
  ('22222222-0001-0001-0001-000000000001', 'Ebtisam AbdulAziz', 'ebtisam-abdulaziz', 'Emirati', 'Dubai', 'Pioneering Emirati conceptual artist whose work explores language, identity, and the female experience through photography, installation, and video.', NULL, '@ebtisam_abdulaziz', false, true, true),
  ('22222222-0002-0002-0002-000000000002', 'Hassan Sharif', 'hassan-sharif', 'Emirati', 'Dubai', 'Legendary Emirati artist known as the father of contemporary art in the UAE. Works across drawing, painting, sculpture, and installation.', NULL, '@hassansharif_art', false, true, true),
  ('22222222-0003-0003-0003-000000000003', 'Shirin Neshat', 'shirin-neshat', 'Iranian', 'New York', 'Internationally acclaimed Iranian-American visual artist and filmmaker known for her explorations of Islamic society, feminism, and exile.', 'https://shirinneshat.com', '@shirinneshatofficial', false, true, true),
  ('22222222-0004-0004-0004-000000000004', 'Ayman Zedani', 'ayman-zedani', 'Saudi', 'Dubai', 'Saudi multidisciplinary artist working in sculpture, installation, and public art. Known for blending traditional Islamic patterns with contemporary forms.', NULL, '@aymanzedani', true, true, true),
  ('22222222-0005-0005-0005-000000000005', 'Nadia Kaabi-Linke', 'nadia-kaabi-linke', 'Tunisian-Ukrainian', 'Dubai', 'Conceptual artist working at the intersection of sociopolitical issues and aesthetics through installation, drawing, and photography.', 'https://nadiakaabilinke.com', '@nadiakaabilinke', true, true, true),
  ('22222222-0006-0006-0006-000000000006', 'Tarek Al-Ghoussein', 'tarek-al-ghoussein', 'Kuwaiti-Palestinian', 'Dubai', 'Photographer and conceptual artist exploring themes of identity, displacement, and belonging through self-portrait series in desolate landscapes.', NULL, '@tareka_g', false, false, false),
  ('22222222-0007-0007-0007-000000000007', 'Rokni Haerizadeh', 'rokni-haerizadeh', 'Iranian', 'Dubai', 'Iranian artist known for large-scale figurative paintings and animations that respond to current events, mixing traditional miniature painting with pop imagery.', NULL, '@roknihaerizadeh', true, true, true),
  ('22222222-0008-0008-0008-000000000008', 'Ramin Haerizadeh', 'ramin-haerizadeh', 'Iranian', 'Dubai', 'Iranian artist working in photography, video, and performance. Collaborates frequently with his brother Rokni and artist Hesam Rahmanian.', NULL, '@raminhaerizadeh', true, true, true),
  ('22222222-0009-0009-0009-000000000009', 'Monira Al Qadiri', 'monira-al-qadiri', 'Kuwaiti', 'Dubai', 'Artist working in video, sculpture, and performance exploring themes of Gulf heritage, oil culture, and mourning rituals.', 'https://moniraalqadiri.com', '@moniraalqadiri', true, true, true),
  ('22222222-0010-0010-0010-000000000010', 'Maitha Hamdan', 'maitha-hamdan', 'Emirati', 'Dubai', 'Emirati visual artist and cultural practitioner exploring themes of cultural identity and memory. Known for intricate calligraphy-inspired installations.', NULL, '@maithahamdan', true, false, false),
  ('22222222-0011-0011-0011-000000000011', 'Faig Ahmed', 'faig-ahmed', 'Azerbaijani', 'Dubai', 'Contemporary artist known for deconstructing traditional Azerbaijani carpet patterns into fluid, pixelated, or melting forms.', 'https://faigahmed.com', '@faigahmedart', true, true, true),
  ('22222222-0012-0012-0012-000000000012', 'Sophia Al-Maria', 'sophia-al-maria', 'Qatari-American', 'Dubai', 'Artist, filmmaker, and author who coined the term ''Gulf Futurism''. Works in video, installation, and writing exploring technology and Arab culture.', 'https://sophiaalaria.com', '@sophia_al_maria', false, true, true),
  ('22222222-0013-0013-0013-000000000013', 'Wael Shawky', 'wael-shawky', 'Egyptian', 'Dubai', 'Egyptian artist known for video works and epic theatrical productions exploring Islamic history and Arab identity through puppets, drawings, and performance.', NULL, '@waelshawky', false, true, true),
  ('22222222-0014-0014-0014-000000000014', 'Moza Al Matrooshi', 'moza-al-matrooshi', 'Emirati', 'Dubai', 'Emerging Emirati sculptor and installation artist exploring themes of sustainability, craft, and the relationship between nature and urban environments.', NULL, '@mozaalmatrooshi', true, false, false),
  ('22222222-0015-0015-0015-000000000015', 'Khalil Rabah', 'khalil-rabah', 'Palestinian', 'Dubai', 'Artist working with found objects, archives, and institutional critique. Known for re-imagining museum collections through a Palestinian political lens.', NULL, '@khalilrabah', true, true, true);
INSERT INTO events (id, title, slug, description, start_date, end_date, opening_date, location, gallery_id, event_type, ticket_info, vip_access, image_url, is_featured) VALUES
  ('33333333-0001-0001-0001-000000000001', 'Echoes of Tomorrow', 'echoes-of-tomorrow', 'A sweeping survey of contemporary Gulf art exploring how artists from the region are imagining and critiquing the future. Featuring 12 artists across painting, sculpture, and video installation.', '2026-03-01 10:00:00+04', '2026-04-15 18:00:00+04', '2026-02-28 19:00:00+04', 'Leila Heller Gallery, Gate Village 4, DIFC', '11111111-0001-0001-0001-000000000009', 'exhibition', 'Free entry', false, NULL, true),
  ('33333333-0002-0002-0002-000000000002', 'Dubai Art Week 2026', 'dubai-art-week-2026', 'The premier annual celebration of the UAE art scene, featuring gallery nights, artist talks, open studios, and special exhibitions across the city.', '2026-03-10 09:00:00+04', '2026-03-16 21:00:00+04', NULL, 'Various venues across Dubai', NULL, 'art_fair', 'Various pricing — some events free', true, NULL, true),
  ('33333333-0003-0003-0003-000000000003', 'Geometry of the Soul', 'geometry-of-the-soul', 'Ayman Zedani''s first major solo exhibition in Dubai, presenting new sculptures and site-specific installations that merge Islamic geometric patterns with futurist aesthetics.', '2026-03-05 10:00:00+04', '2026-05-01 18:00:00+04', '2026-03-04 19:30:00+04', 'The Third Line, Al Quoz', '11111111-0001-0001-0001-000000000002', 'exhibition', 'Free entry', false, NULL, true),
  ('33333333-0004-0004-0004-000000000004', 'Artist Talk: Monira Al Qadiri on Gulf Futurism', 'artist-talk-monira-al-qadiri', 'In conversation with cultural critic Rahel Aima, artist Monira Al Qadiri discusses her practice, the aesthetics of oil culture, and what Gulf Futurism means today.', '2026-03-12 18:30:00+04', '2026-03-12 20:30:00+04', NULL, 'Alserkal Avenue, Community Hall', NULL, 'talk', 'AED 50 — register online', false, NULL, false),
  ('33333333-0005-0005-0005-000000000005', 'Threads of Memory', 'threads-of-memory', 'Faig Ahmed''s latest body of work challenges the familiar forms of traditional carpets, weaving digital aesthetics into ancient craft. A meditation on identity and transformation.', '2026-02-15 10:00:00+04', '2026-03-30 18:00:00+04', '2026-02-14 19:00:00+04', 'Isabelle van den Eynde Gallery, Alserkal Avenue', '11111111-0001-0001-0001-000000000005', 'exhibition', 'Free entry', false, NULL, false),
  ('33333333-0006-0006-0006-000000000006', 'Silk Road Now: Contemporary Connections', 'silk-road-now', 'A group exhibition examining how artists across the historic Silk Road corridor are responding to trade, migration, and cultural exchange in the 21st century.', '2026-03-20 10:00:00+04', '2026-06-01 18:00:00+04', '2026-03-19 19:00:00+04', 'Opera Gallery, Gate Village 3, DIFC', '11111111-0001-0001-0001-000000000016', 'exhibition', 'Free entry', false, NULL, false),
  ('33333333-0007-0007-0007-000000000007', 'Opening Night: Ebtisam AbdulAziz', 'opening-ebtisam-abdulaziz', 'Private opening night for the new exhibition by pioneering Emirati artist Ebtisam AbdulAziz. Exclusive access to the artist and curators.', '2026-03-25 19:00:00+04', '2026-03-25 22:00:00+04', NULL, 'Majlis Gallery, Al Fahidi', '11111111-0001-0001-0001-000000000021', 'opening', 'Invitation only', true, NULL, false),
  ('33333333-0008-0008-0008-000000000008', 'Photography Masterclass: Tarek Al-Ghoussein', 'photography-masterclass-tarek', 'A two-day intensive masterclass with internationally renowned photographer Tarek Al-Ghoussein, focusing on conceptual photography and self-portraiture.', '2026-04-05 10:00:00+04', '2026-04-06 17:00:00+04', NULL, 'Alserkal Avenue, Workshop Space B', NULL, 'workshop', 'AED 800 for both days — limited to 15 participants', false, NULL, false),
  ('33333333-0009-0009-0009-000000000009', 'The Weight of Words: Nadia Kaabi-Linke', 'weight-of-words', 'An immersive solo exhibition exploring linguistic and physical borders. Kaabi-Linke''s large-scale installations use text, trace, and material to question systems of inclusion and exclusion.', '2026-03-15 10:00:00+04', '2026-05-15 18:00:00+04', '2026-03-14 19:00:00+04', 'Warehouse421, Abu Dhabi', NULL, 'exhibition', 'AED 25 per person', false, NULL, true),
  ('33333333-0010-0010-0010-000000000010', 'Gulf Futures Forum', 'gulf-futures-forum', 'A two-day symposium bringing together artists, curators, critics, and cultural policymakers to discuss the future of the Gulf art scene. Keynotes, panels, and performances.', '2026-04-10 09:00:00+04', '2026-04-11 19:00:00+04', NULL, 'Mohammed Bin Rashid Library, Dubai Creek', NULL, 'talk', 'AED 200 for both days — AED 100 for single day', true, NULL, false),
  ('33333333-0011-0011-0011-000000000011', 'Carpet as Canvas', 'carpet-as-canvas', 'A group show bringing together artists who use the carpet and textile as their primary medium, exploring the intersection of craft, tradition, and contemporary art.', '2026-04-01 10:00:00+04', '2026-05-30 18:00:00+04', '2026-03-31 19:00:00+04', 'Etihad Modern Art Gallery, Downtown', NULL, 'exhibition', 'Free entry', false, NULL, false),
  ('33333333-0012-0012-0012-000000000012', 'Sound and Fury: Live Performance Night', 'sound-and-fury-performance', 'An evening of live performance art, sound installations, and experimental video by five emerging artists from the UAE and wider Gulf region.', '2026-03-22 20:00:00+04', '2026-03-22 23:00:00+04', NULL, 'Alserkal Avenue, A4 Space', NULL, 'performance', 'AED 75 at the door', false, NULL, false),
  ('33333333-0013-0013-0013-000000000013', 'Rokni & Ramin: Double Vision', 'rokni-ramin-double-vision', 'The first joint exhibition in Dubai by brothers Rokni and Ramin Haerizadeh, featuring new paintings, animations, and collaborative installations created during their Dubai residency.', '2026-05-10 10:00:00+04', '2026-07-01 18:00:00+04', '2026-05-09 19:30:00+04', 'The Third Line, Al Quoz', '11111111-0001-0001-0001-000000000002', 'exhibition', 'Free entry', true, NULL, true),
  ('33333333-0014-0014-0014-000000000014', 'Khalil Rabah: The Palestine Museum (Dubai Edition)', 'khalil-rabah-palestine-museum', 'An ongoing conceptual museum project by Palestinian artist Khalil Rabah, reimagined and reinstalled for a Dubai context. The work challenges ideas of nationhood, collection, and cultural heritage.', '2026-03-08 10:00:00+04', '2026-04-30 18:00:00+04', '2026-03-07 19:00:00+04', 'Leila Heller Gallery, DIFC', '11111111-0001-0001-0001-000000000009', 'exhibition', 'Free entry', false, NULL, false),
  ('33333333-0015-0015-0015-000000000015', 'Young Collectors Evening', 'young-collectors-evening', 'An exclusive evening for art collectors under 40, featuring curator-led tours, artist introductions, and a selection of affordable works by emerging regional artists.', '2026-03-18 19:00:00+04', '2026-03-18 22:00:00+04', NULL, 'Opera Gallery, DIFC', '11111111-0001-0001-0001-000000000016', 'opening', 'AED 150 — includes champagne reception', true, NULL, false),
  ('33333333-0016-0016-0016-000000000016', 'Moza Al Matrooshi: Grown Here', 'moza-al-matrooshi-grown-here', 'A debut solo exhibition by Emirati sculptor Moza Al Matrooshi, presenting works that explore the relationship between organic growth, traditional craft, and Dubai''s rapid urbanisation.', '2026-06-01 10:00:00+04', '2026-07-15 18:00:00+04', '2026-05-31 19:00:00+04', 'Alserkal Avenue, Gallery Space', NULL, 'exhibition', 'Free entry', false, NULL, false),
  ('33333333-0017-0017-0017-000000000017', 'Printmaking Workshop: Arabic Calligraphy Monoprints', 'printmaking-workshop-calligraphy', 'A hands-on workshop exploring the crossover between traditional Arabic calligraphy and modern printmaking techniques. No prior experience required.', '2026-03-28 10:00:00+04', '2026-03-28 16:00:00+04', NULL, 'Mohammed Bin Rashid Library, Art Studios', NULL, 'workshop', 'AED 350 including materials', false, NULL, false),
  ('33333333-0018-0018-0018-000000000018', 'Sophia Al-Maria: Black Friday Redux', 'sophia-al-maria-black-friday', 'A new video installation by Gulf Futurism pioneer Sophia Al-Maria, examining consumer culture, digital identity, and the aesthetics of the mall in the post-pandemic Gulf.', '2026-04-15 10:00:00+04', '2026-06-15 18:00:00+04', '2026-04-14 19:00:00+04', 'Isabelle van den Eynde Gallery, Alserkal', '11111111-0001-0001-0001-000000000005', 'exhibition', 'Free entry', false, NULL, false),
  ('33333333-0019-0019-0019-000000000019', 'Art Dubai 2026 Preview Dinner', 'art-dubai-2026-preview-dinner', 'An exclusive VIP preview dinner and private viewing on the eve of Art Dubai 2026, with collectors, artists, and gallerists from across the globe.', '2026-03-11 19:30:00+04', '2026-03-11 23:00:00+04', NULL, 'Madinat Jumeirah, Arena', NULL, 'opening', 'By invitation only', true, NULL, true),
  ('33333333-0020-0020-0020-000000000020', 'Wael Shawky: Drama 1882', 'wael-shawky-drama-1882', 'The UAE premiere of Wael Shawky''s acclaimed epic trilogy, a staged opera retelling the story of the 1882 Urabi Revolt through puppetry, costumes, and classical Arabic music.', '2026-03-13 19:00:00+04', '2026-03-14 21:00:00+04', NULL, 'Alserkal Avenue, A4 Space', NULL, 'performance', 'AED 120 per night, AED 200 for both nights', true, NULL, true);
