INSERT INTO news (id, title, slug, content, related_gallery_id, related_artist_id, publish_date) VALUES
  ('44444444-0001-0001-0001-000000000001', 'Dubai Art Week 2026 Announces Record Participation', 'dubai-art-week-2026-record', '<h2>Record numbers for the region''s premier art event</h2><p>Dubai Art Week 2026 has announced its most ambitious programme yet, with over 80 galleries, museums, and arts institutions participating across the emirate. This year''s edition focuses on the theme of "Crossings" — exploring migration, trade routes, and cultural exchange in the contemporary Gulf.</p><p>The week-long celebration begins on March 10th and features a special collaboration between the Mohammed Bin Rashid Library and Alserkal Avenue, creating a cultural corridor from the Creek to Al Quoz.</p><p>Highlights include a new commission by Monira Al Qadiri for the Dubai Fountain, a major retrospective of Hassan Sharif''s work at the MBR Library, and the debut of three new galleries in the DIFC district.</p>', NULL, NULL, '2026-03-01 09:00:00+04'),
  ('44444444-0002-0002-0002-000000000002', 'Leila Heller Gallery Expands to New Alserkal Space', 'leila-heller-alserkal-expansion', '<h2>Iconic DIFC gallery opens second Dubai location</h2><p>Leila Heller Gallery has announced the opening of a second Dubai space in Alserkal Avenue, set to launch in September 2026. The new 800-square-metre space will focus exclusively on emerging artists from the MENA region and Central Asia.</p><p>Gallery director Leila Heller said the expansion reflects the "extraordinary energy" coming from the regional art scene. The Alserkal space will host four to six exhibitions per year, with a focus on first-time solo shows by artists under 35.</p><p>The new space will also include a dedicated residency studio for two artists per season, selected through an open application process.</p>', '11111111-0001-0001-0001-000000000009', NULL, '2026-02-20 10:00:00+04'),
  ('44444444-0003-0003-0003-000000000003', 'Ebtisam AbdulAziz Represents UAE at Venice Biennale 2026', 'ebtisam-abdulaziz-venice-2026', '<h2>Pioneering Emirati artist chosen for national pavilion</h2><p>The UAE pavilion at the 2026 Venice Biennale will be represented by pioneering conceptual artist Ebtisam AbdulAziz, it has been announced by the UAE Ministry of Culture. AbdulAziz, one of the UAE''s most internationally recognized artists, will present a new commission titled "Unwritten," exploring the politics of language, memory, and erasure.</p><p>The announcement has been widely celebrated by the Dubai art community. The Third Line gallery, which represents AbdulAziz, called it "a landmark moment for Emirati art and its place in the global conversation."</p><p>The Venice Biennale opens on April 19th, 2026, with the UAE Pavilion located in the Arsenale.</p>', NULL, '22222222-0001-0001-0001-000000000001', '2026-02-15 09:00:00+04'),
  ('44444444-0004-0004-0004-000000000004', 'Alserkal Avenue Launches New Arts Residency Programme', 'alserkal-residency-programme-2026', '<h2>Six international artists to receive studios and stipends</h2><p>Alserkal Avenue has announced the launch of its most ambitious residency programme to date, offering six international artists a three-month residency in Dubai including a studio, living stipend, and production support.</p><p>The 2026 cohort includes artists from Egypt, Pakistan, South Korea, Brazil, and the Netherlands. Each artist will engage with the Dubai community through open studio days, public talks, and a final group exhibition in November 2026.</p><p>Applications for the 2027 residency will open in October 2026. Alserkal Avenue has allocated AED 500,000 for the programme, funded by a combination of gallery partners and the Dubai Culture & Arts Authority.</p>', NULL, NULL, '2026-02-10 11:00:00+04'),
  ('44444444-0005-0005-0005-000000000005', 'Mohammed Bin Rashid Library Unveils Major Hassan Sharif Archive', 'mbr-library-hassan-sharif-archive', '<h2>Landmark archive opens to researchers and the public</h2><p>The Mohammed Bin Rashid Library has unveiled a comprehensive archive dedicated to the late Hassan Sharif, widely regarded as the father of contemporary art in the UAE. The archive includes over 4,000 works on paper, notebooks, correspondence, and documentation of major installations spanning five decades of the artist''s practice.</p><p>The archive, developed in partnership with the Hassan Sharif Foundation, will be accessible to researchers by appointment and will feature a permanent rotating display in the library''s Cultural Gallery on the fourth floor.</p><p>A major retrospective exhibition drawing from the archive is planned for late 2026, in collaboration with several international institutions.</p>', NULL, '22222222-0002-0002-0002-000000000002', '2026-01-25 09:00:00+04');
